/**
 * Maven processors are defined like this.
 * <pre>{@code
 *       <plugin>
 *         <groupId>org.bsc.maven</groupId>
 *         <artifactId>maven-processor-plugin</artifactId>
 *         <executions>
 *           <execution>
 *             <id>process</id>
 *             [...]
 *             <configuration>
 *               <processors>
 *                 <processor>XXXProcessor</processor>
 *               </processors>
 *             </configuration>
 *           </execution>
 *         </executions>
 *       </plugin>
 * }</pre>
 */
@Override
public Set<String> collectUsedClassesFromProcessors() {
  getLog().debug("# collectUsedClassesFromProcessors()");
  return Optional.ofNullable(project.getPlugin("org.bsc.maven:maven-processor-plugin"))
      .map(plugin -> plugin.getExecutionsAsMap().get("process"))
      .map(exec -> exec.getConfiguration()) // Using Maven's built-in configuration API
      .map(config -> config.getChild("processors"))
      .map(child -> {
          if (child != null && child.getChildren() != null) {
              return Arrays.stream(child.getChildren())
                  .map(childElement -> childElement.getValue())
                  .collect(Collectors.toSet());
          }
          return of();
      })
      .orElse(of());
}

